@AzureFunction(name="process_files", methods=["post"])
def process_files(req: HttpRequest) -> HttpResponseDefault:
    # Get the blob storage connection string from environment variables
    blob_storage_conn_str = os.environ["BLOB_STORAGE_CONN_STR"]
    
    # Create a BlobServiceClient object to interact with Blob Storage
    blob_service_client = BlobServiceClient.from_connection_string(blob_storage_conn_str)
    
    # Get the Cosmos DB endpoint and key from environment variables
    cosmos_db_endpoint = os.environ["COSMOS_DB_ENDPOINT"]
    cosmos_db_key = os.environ["COSMOS_DB_KEY"]
    
    # Create a CosmosClient object to interact with Cosmos DB
    cosmos_client = CosmosClient(cosmos_db_endpoint, cosmos_db_key)
    
