    event_grid_key = os.environ["EVENT_GRID_KEY"]
    
    # Create an EventGridClient object to interact with Event Grid
    event_grid_client = EventGridClient(event_grid_endpoint, event_grid_key)
    
    # Get the blob name from the request body
    blob_name = req.get_json().get("blobName")
    
    # Check if the blob exists in Blob Storage
    container_client = blob_service_client.get_container_client(req.get_json().get("container"))
    blob_client = container_client.get_blob_client(blob_name)
    if not blob_client.exists():
        return HttpResponseDefault(status_code=404, body="Blob not found")
    
    # Read the contents of the blob
    blob_data = blob_client.download_blob().content_as_text()
    
    # Process the data and write it to Cosmos DB
    database = cosmos_client.get_database_client("mydatabase")
    container = database.get_container_client("mycontainer")
    item = {"id": 1, "data": blob_data}
    container.upsert_item(item)
    
    # Send a notification via Event Grid
    event_grid_client.send_events(
        req.get_json().get("container"),
        [
            {
                "topic": "/subscriptions/{subscriptionId}/resourceGroups/{resourceGroupName}/providers/Microsoft.Storage/storageAccounts/{storageAccountName}",
                "subject": f"/blobServices/default/containers/{req.get_json().get('container')}/blobs/{blob_name}",
                "eventType": "Microsoft.Storage.BlobCreated",
                "eventTime": datetime.now().isoformat(),
            }
        ],
    )
    
    return HttpResponseDefault(status_code=200, body="File processed successfully")

